fn solve(n: i64, edges: Vec<Vec<i64>>, label: String) -> i64 {
    let n = n as usize;
    let mut graph = vec![vec![]; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        graph[u].push(v);
        graph[v].push(u);
    }
    let labels: Vec<char> = label.chars().collect();
    let total_masks = 1 << n;
    let mut visited = vec![vec![vec![false; n]; n]; total_masks];
    let mut q = Vec::new();
    let mut max_ans = 1;

    for i in 0..n {
        let mask = 1 << i;
        visited[mask][i][i] = true;
        q.push((mask, i, i, labels[i].to_string()));
    }

    let is_palindrome = |s: &str| -> bool {
        let bytes = s.as_bytes();
        let len = bytes.len();
        for i in 0..len / 2 {
            if bytes[i] != bytes[len - 1 - i] {
                return false;
            }
        }
        true
    };

    let mut idx = 0;
    while idx < q.len() {
        let (mask, i, j, s) = q[idx].clone();
        for &k in &graph[i] {
            if mask & (1 << k) != 0 {
                continue;
            }
            let new_mask = mask | (1 << k);
            if !visited[new_mask][k][j] {
                visited[new_mask][k][j] = true;
                let new_s = format!("{}{}", labels[k], s);
                if is_palindrome(&new_s) {
                    max_ans = max_ans.max(new_s.len() as i64);
                }
                q.push((new_mask, k, j, new_s));
            }
        }
        for &k in &graph[j] {
            if mask & (1 << k) != 0 {
                continue;
            }
            let new_mask = mask | (1 << k);
            if !visited[new_mask][i][k] {
                visited[new_mask][i][k] = true;
                let new_s = format!("{}{}", s, labels[k]);
                if is_palindrome(&new_s) {
                    max_ans = max_ans.max(new_s.len() as i64);
                }
                q.push((new_mask, i, k, new_s));
            }
        }
        idx += 1;
    }

    max_ans
}
