fn solve(n: i64, edges: Vec<Vec<i64>>, label: String) -> i64 {
    let n = n as usize;
    let mut graph = vec![vec![]; n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        graph[u].push(v);
        graph[v].push(u);
    }
    let lb = label.as_bytes();
    let size = 1 << n;
    let mut dp = vec![vec![vec![-1; n]; n]; size];

    for i in 0..n {
        let mask = 1 << i;
        dp[mask][i][i] = 1;
    }

    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        if lb[u] == lb[v] {
            let mask = (1 << u) | (1 << v);
            dp[mask][u][v] = 2;
            dp[mask][v][u] = 2;
        }
    }

    let mut ans = 1;
    for mask in 0..size {
        for u in 0..n {
            if (mask >> u) & 1 == 0 {
                continue;
            }
            for v in 0..n {
                if (mask >> v) & 1 == 0 {
                    continue;
                }
                if dp[mask][u][v] == -1 {
                    continue;
                }
                if dp[mask][u][v] > ans {
                    ans = dp[mask][u][v];
                }
                for &x in &graph[u] {
                    if (mask >> x) & 1 != 0 {
                        continue;
                    }
                    for &y in &graph[v] {
                        if (mask >> y) & 1 != 0 || x == y {
                            continue;
                        }
                        if lb[x] == lb[y] {
                            let new_mask = mask | (1 << x) | (1 << y);
                            let new_val = dp[mask][u][v] + 2;
                            if new_val > dp[new_mask][x][y] {
                                dp[new_mask][x][y] = new_val;
                                dp[new_mask][y][x] = new_val;
                            }
                        }
                    }
                }
            }
        }
    }

    ans
}
