fn solve(n: i64, edges: Vec<Vec<i64>>, label: String) -> i64 {
    let n = n as usize;
    let label_chars: Vec<char> = label.chars().collect();
    let mut adj: Vec<Vec<usize>> = vec![vec![]; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj[u].push(v);
        adj[v].push(u);
    }

    let mut visited = vec![false; n];
    let mut max_pal_len = 1;

    for start in 0..n {
        let mut path = Vec::new();
        let mut path_labels = String::new();
        dfs(
            start,
            &mut visited,
            &mut path,
            &mut path_labels,
            &label_chars,
            &adj,
            &mut max_pal_len,
        );
    }

    max_pal_len
}

fn dfs(
    node: usize,
    visited: &mut Vec<bool>,
    path: &mut Vec<usize>,
    path_labels: &mut String,
    label_chars: &Vec<char>,
    adj: &Vec<Vec<usize>>,
    max_pal_len: &mut i64,
) {
    visited[node] = true;
    path.push(node);
    path_labels.push(label_chars[node]);

    let s = &path_labels;
    if is_palindrome(s) {
        *max_pal_len = std::cmp::max(*max_pal_len, s.len() as i64);
    }

    for &neighbor in &adj[node] {
        if !visited[neighbor] {
            dfs(
                neighbor,
                visited,
                path,
                path_labels,
                label_chars,
                adj,
                max_pal_len,
            );
        }
    }

    path.pop();
    path_labels.pop();
    visited[node] = false;
}

fn is_palindrome(s: &str) -> bool {
    let bytes = s.as_bytes();
    let n = bytes.len();
    for i in 0..n / 2 {
        if bytes[i] != bytes[n - 1 - i] {
            return false;
        }
    }
    true
}
